#include <stdio.h>

int main() {
    int T, N, K, value, count;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d %d", &N, &K);
        count = 0;
        for (int i = 0; i < N; ++i) {
            scanf("%d", &value);
            if ((value + K) % 7 == 0) ++count;
        }
        printf("%d\n", count);
    }
    return 0;
}

