import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        K = int(next(it))
        count = 0
        for _ in range(N):
            v = int(next(it))
            if (v + K) % 7 == 0:
                count += 1
        out_lines.append(str(count))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

